import React from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Dashboard from './pages/Dashboard';
import Screening from './pages/Screening';
import Chatbot from './pages/Chatbot';
import Counselors from './pages/Counselors';
import Therapy from './pages/Therapy';
import ParentForm from './pages/ParentForm';
import Login from './pages/Login';

export default function App(){
  return (
    <BrowserRouter>
      <div className="topnav">
        <Link to="/">Home</Link> | <Link to="/dashboard">Dashboard</Link> | <Link to="/screening">Screening</Link> | <Link to="/chat">Chatbot</Link> | <Link to="/counselors">Counselors</Link> | <Link to="/therapy">Therapy</Link> | <Link to="/parent">Parent Form</Link>
      </div>
      <Routes>
        <Route path="/" element={<Home/>}/>
        <Route path="/login" element={<Login/>}/>
        <Route path="/dashboard" element={<Dashboard/>}/>
        <Route path="/screening" element={<Screening/>}/>
        <Route path="/chat" element={<Chatbot/>}/>
        <Route path="/counselors" element={<Counselors/>}/>
        <Route path="/therapy" element={<Therapy/>}/>
        <Route path="/parent" element={<ParentForm/>}/>
      </Routes>
    </BrowserRouter>
  );
}
